const v15ReadA={id:"v15-read-a",kind:"passage",label:"Passage for Items 69-72",title:"Public Hearing Access",description:"A provincial board streamed its budget hearing and accepted questions through an online form. The first session drew many viewers, but several questions arrived after the relevant agenda item had ended. For the next hearing, staff published a timed agenda, displayed the current topic on screen, and assigned one moderator to group similar questions. More questions were answered during the proper segment. However, residents with unstable internet still struggled to participate, so the board retained an in-person desk and a telephone line rather than treating the stream as the only channel.",alt:"Passage about improving a streamed budget hearing with a timed agenda, topic labels, and grouped questions while retaining in-person and telephone access for residents with unstable internet."};
const v15ReadB={id:"v15-read-b",kind:"passage",label:"Babasahin para sa Aytem 73-76",title:"Imbakan ng Tubig-Ulan",description:"Naglagay ang isang paaralan ng mga tangke upang ipunin ang tubig-ulan para sa paglilinis ng sahig at pagdidilig. Sa unang buwan, madalas umapaw ang isang tangke samantalang kulang ang tubig sa hardin sa kabilang gusali. Sinukat ng pangkat ang lawak ng bawat bubong, dami ng ulan, at aktuwal na gamit. Inilipat nila ang isang tangke sa mas malaking bubong at nilagyan ng simpleng panukat ang bawat imbakan. Nabawasan ang pag-apaw at mas maayos ang paglalaan, ngunit ipinagbawal pa rin ang pag-inom sa naipong tubig dahil wala itong sistemang panlinis para sa inuming tubig.",alt:"Teksto tungkol sa paaralang nag-ayos ng lokasyon at pagsukat ng mga tangke ng tubig-ulan para mabawasan ang pag-apaw at mapahusay ang laan, ngunit hindi ito ginamit na inumin."};
const v15ReadC={id:"v15-read-c",kind:"passage",label:"Passage for Items 77-80",title:"Accessible Digital Queue",description:"A licensing office replaced a single physical line with numbered appointments. Initial waiting time fell, yet clients who arrived without smartphones could not confirm their slots. Staff added a kiosk with large text, audio prompts, and a help button, then tested it with older adults and clients with low vision. Completion improved, but the office also kept a staffed counter for transactions that required interpretation or assistance. Managers concluded that automation was useful only when alternative access and actual user testing were part of the design.",alt:"Passage about a licensing office improving a digital appointment queue through an accessible kiosk, user testing, and a staffed alternative for clients needing assistance."};
const v15DataA={id:"v15-data-a",kind:"table",label:"Table for Items 155-158",title:"Relief Pack Assembly",description:"Workers, hours, packed boxes, and rejected boxes by team. Unit: people, hours, and boxes.",headers:["Team","Workers","Hours","Packed","Rejected"],rows:[["Alpha",8,6,384,12],["Bravo",10,5,420,15],["Charlie",6,7,336,6],["Delta",9,6,432,9]],legend:["Accepted boxes equal Packed minus Rejected","Worker-hours equal Workers times Hours"],alt:"Alpha: 8 workers, 6 hours, 384 packed, 12 rejected. Bravo: 10, 5, 420, 15. Charlie: 6, 7, 336, 6. Delta: 9, 6, 432, 9."};
const v15DataB={id:"v15-data-b",kind:"line-table",label:"Graph for Items 159-162",title:"Rainwater Storage",description:"Tank level at the start and end of four weeks, with collected and used water. Unit: liters.",headers:["Week","Start","Collected","Used","End"],rows:[["Week 1",1200,900,700,1400],["Week 2",1400,600,850,1150],["Week 3",1150,1100,750,1500],["Week 4",1500,500,920,1080]],legend:["Cyan line: Start level","Blue line: End level"],alt:"Week 1: start 1,200 liters, collect 900, use 700, end 1,400. Week 2: 1,400, 600, 850, 1,150. Week 3: 1,150, 1,100, 750, 1,500. Week 4: 1,500, 500, 920, 1,080."};
